package com.korit.clovapi.domain.plan.controller;
import com.korit.clovapi.domain.plan.dto.*; import com.korit.clovapi.domain.plan.service.PlanService; import com.korit.clovapi.global.response.ApiResponse; import jakarta.validation.Valid; import org.springframework.security.core.Authentication; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1") public class ChecklistController {private final PlanService s;public ChecklistController(PlanService s){this.s=s;}private long u(Authentication a){return (Long)a.getPrincipal();}@PostMapping("/plans/{planId}/checklists") public ApiResponse<PlanResponses.Checklist> add(Authentication a,@PathVariable long planId,@Valid @RequestBody PlanRequests.Checklist r){return ApiResponse.success(s.addChecklist(planId,u(a),r));}@PatchMapping("/checklists/{checklistId}") public ApiResponse<PlanResponses.Checklist> update(Authentication a,@PathVariable long checklistId,@Valid @RequestBody PlanRequests.ChecklistUpdate r){return ApiResponse.success(s.updateChecklist(checklistId,u(a),r));}@DeleteMapping("/checklists/{checklistId}") public ApiResponse<Void> delete(Authentication a,@PathVariable long checklistId){s.deleteChecklist(checklistId,u(a));return ApiResponse.success(null);}}
